const input = $input.first();
const raw = ($json.tool_input && typeof $json.tool_input === 'object') ? $json.tool_input : $json;
const message = String(raw.message || raw.media_caption || '').trim();
const fileName = String(raw.media_filename || '').trim();
const mime = String(raw.media_mime_type || '').trim().toLowerCase();
const ext = fileName.includes('.') ? fileName.split('.').pop().toLowerCase() : '';
const sourceType = String(raw.source_type || (raw.media_id ? 'document' : 'text')).trim() || 'text';
return [{
  json: {
    ...raw,
    chat_id: String(raw.chat_id || ''),
    store_id: raw.store_id || null,
    message,
    source_type: sourceType,
    media_id: String(raw.media_id || ''),
    media_mime_type: mime,
    media_filename: fileName,
    media_caption: String(raw.media_caption || ''),
    media_ext: ext,
    test_file_base64: String(raw.test_file_base64 || ''),
    test_file_name: String(raw.test_file_name || fileName || ''),
    test_file_mime_type: String(raw.test_file_mime_type || mime || ''),
    test_mode: raw.test_mode === true,
  },
  binary: input?.binary || {},
}];

const input = $input.first();
const d = $('Normalize Input').first().json;
const binary = input?.binary || {};
const hasInlineBinary = !!String(d.test_file_base64 || '').trim();
const hasBinary = !!binary.data || hasInlineBinary;
const mime = String(d.media_mime_type || '').toLowerCase();
const ext = String(d.media_ext || '').toLowerCase();

const isSpreadsheet = /sheet|excel|spreadsheet/.test(mime) || ['xls', 'xlsx'].includes(ext);
const isPdf = mime === 'application/pdf' || ext === 'pdf';
const isImage = mime.startsWith('image/') || ['png', 'jpg', 'jpeg', 'webp'].includes(ext);

let route = 'error';
let parse_mode = 'unsupported';
let error_message = '';

if (!d.chat_id) {
  error_message = 'Missing owner chat ID for import.';
} else if (!(hasBinary || d.media_id)) {
  error_message = 'I could not find a file to import. Please send an XLS, XLSX, PDF, JPG, or PNG stock sheet.';
} else if (isSpreadsheet) {
  route = hasBinary ? 'direct_binary' : 'download_binary';
  parse_mode = 'sheet';
} else if (isPdf) {
  route = hasBinary ? 'direct_binary' : 'download_binary';
  parse_mode = 'document';
} else if (isImage) {
  route = hasBinary ? 'direct_binary' : 'download_binary';
  parse_mode = 'image';
} else {
  error_message = 'Unsupported file type. Please send an XLS, XLSX, PDF, JPG, or PNG stock sheet.';
}

return [{
  json: {
    ...d,
    route,
    parse_mode,
    error_message,
  },
  binary,
}];

const input = $input.first();
const d = $('Determine Import Source').first().json || {};
if (String(d.test_file_base64 || '').trim()) {
  return [{
    json: d,
    binary: {
      data: {
        data: String(d.test_file_base64 || ''),
        mimeType: String(d.test_file_mime_type || d.media_mime_type || 'application/octet-stream'),
        fileName: String(d.test_file_name || d.media_filename || 'owner_upload'),
      },
    },
  }];
}
return [{ json: d, binary: input?.binary || {} }];

const input = $input.first();
const base = $('Determine Import Source').first().json;
const meta = $('Get WhatsApp Media Metadata').first().json || {};
return [{
  json: {
    ...base,
    media_mime_type: String(meta.mime_type || base.media_mime_type || ''),
    media_filename: String(base.media_filename || meta.file_name || base.media_id || 'owner_upload'),
    media_size: meta.file_size || null,
  },
  binary: input?.binary || {},
}];

const raw = $input.first().json || {};
const pickText = (value) => {
  if (typeof value === 'string' && value.trim()) return value.trim();
  if (Array.isArray(value)) {
    for (const entry of value) {
      const nested = pickText(entry);
      if (nested) return nested;
    }
    return '';
  }
  if (value && typeof value === 'object') {
    for (const key of ['output', 'text', 'mergedResponse', 'completion', 'content', 'response', 'result']) {
      if (typeof value[key] === 'string' && value[key].trim()) return value[key].trim();
    }
    if (Array.isArray(value.content)) {
      for (const part of value.content) {
        if (typeof part?.text === 'string' && part.text.trim()) return part.text.trim();
      }
    }
  }
  return '';
};

const extractJson = (value) => {
  const text = pickText(value);
  if (!text) return null;
  try { return JSON.parse(text); } catch {}
  const block = text.match(/\{[\s\S]*\}/);
  if (block) {
    try { return JSON.parse(block[0]); } catch {}
  }
  const tick = String.fromCharCode(96).repeat(3);
  const fenced = text.replace(new RegExp(tick + 'json|' + tick, 'gi'), '').trim();
  try { return JSON.parse(fenced); } catch {}
  return null;
};

const parsed = extractJson(raw) || {};
const documentConfidenceRaw = parsed.document_confidence ?? parsed.confidence ?? parsed.ocr_confidence ?? null;
const documentConfidence = documentConfidenceRaw === null || documentConfidenceRaw === undefined || documentConfidenceRaw === ''
  ? null
  : (Number(documentConfidenceRaw) > 1 && Number(documentConfidenceRaw) <= 100 ? Number(documentConfidenceRaw) / 100 : Number(documentConfidenceRaw));
const rows = Array.isArray(parsed.rows) ? parsed.rows : [];
const invalid = Array.isArray(parsed.invalid_rows) ? parsed.invalid_rows : [];
const qualityNotes = Array.isArray(parsed.quality_notes) ? parsed.quality_notes : [];
const items = [];
for (const row of rows) {
  items.push({
    json: {
      item_name: row.item_name || row.name || row.product || '',
      price: row.price,
      stock: row.stock,
      unit: row.unit || '',
      category: row.category || '',
      brand: row.brand || '',
      raw_line: row.raw_line || '',
      row_confidence: row.row_confidence ?? row.confidence ?? row.ocr_confidence ?? null,
      review_reason: row.review_reason || row.reason || '',
      needs_review: row.needs_review === true,
      document_confidence: Number.isFinite(documentConfidence) ? documentConfidence : null,
      quality_notes: qualityNotes,
    },
  });
}
for (const row of invalid) {
  items.push({
    json: {
      item_name: row.item_name || row.name || '',
      raw_line: row.raw_line || row.source || '',
      reason: row.reason || 'invalid row',
      invalid: true,
      row_confidence: row.row_confidence ?? row.confidence ?? row.ocr_confidence ?? null,
      document_confidence: Number.isFinite(documentConfidence) ? documentConfidence : null,
      quality_notes: qualityNotes,
    },
  });
}
if (!items.length) {
  items.push({
    json: {
      invalid: true,
      raw_line: '',
      reason: 'no rows parsed',
      document_confidence: Number.isFinite(documentConfidence) ? documentConfidence : null,
      quality_notes: qualityNotes,
    },
  });
}
return items;

let meta = {};
try {
  meta = $('Attach Downloaded Binary').first().json || {};
} catch {}
if (!meta || Object.keys(meta).length === 0) {
  try {
    meta = $('Pass Existing Binary').first().json || {};
  } catch {}
}
if (!meta || Object.keys(meta).length === 0) {
  try {
    meta = $('Determine Import Source').first().json || {};
  } catch {}
}
const inventory = $('Load Inventory Snapshot').all().map((item) => item.json || {}).filter((row) => row && row.item_name);
const inputRows = $input.all().map((item) => item.json || {});
const parseMode = String(meta.parse_mode || '').toLowerCase();
const ocrBacked = parseMode === 'image' || parseMode === 'document';
const documentConfidenceThreshold = 0.88;
const rowConfidenceThreshold = 0.9;

const normalizeName = (value) => String(value || '').toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim().replace(/\s+/g, ' ');
const toNum = (value) => value === null || value === undefined || value === '' ? null : Number(value);
const words = (value) => normalizeName(value).split(' ').filter(Boolean);
const normalizeConfidence = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const num = Number(value);
  if (!Number.isFinite(num)) return null;
  if (num > 1 && num <= 100) return num / 100;
  if (num >= 0 && num <= 1) return num;
  return null;
};

function scoreCandidate(target, candidate) {
  if (!target || !candidate) return 0;
  if (target === candidate) return 1;
  if (candidate.startsWith(target) || target.startsWith(candidate)) return 0.9;
  if (candidate.includes(target) || target.includes(candidate)) return 0.82;
  const a = new Set(words(target));
  const b = new Set(words(candidate));
  const common = [...a].filter((word) => b.has(word)).length;
  const union = new Set([...a, ...b]).size || 1;
  return common / union;
}

function buildSku(name, rows, reserved) {
  const used = new Set(rows.map((row) => String(row.sku || '').trim()).filter(Boolean).map((sku) => sku.toUpperCase()));
  for (const value of reserved) used.add(String(value || '').trim().toUpperCase());
  let baseSku = normalizeName(name).toUpperCase().replace(/[^A-Z0-9]+/g, '_').replace(/^_+|_+$/g, '').slice(0, 18);
  if (!baseSku) baseSku = 'ITEM';
  let sku = baseSku;
  let suffix = 2;
  while (used.has(sku)) {
    sku = baseSku.slice(0, 14) + '_' + suffix;
    suffix += 1;
  }
  reserved.add(sku);
  return sku;
}

function resolveItem(name) {
  const normalized = normalizeName(name);
  const exact = inventory.filter((row) => normalizeName(row.item_name) === normalized);
  const activeExact = exact.filter((row) => row.is_active !== false);
  if (activeExact.length === 1) return { status: 'exact', row: activeExact[0], matches: [activeExact[0].item_name] };
  if (exact.length === 1) return { status: 'inactive_exact', row: exact[0], matches: [exact[0].item_name] };
  const fuzzy = inventory.map((row) => ({ row, score: scoreCandidate(normalized, normalizeName(row.item_name)) }))
    .filter((row) => row.score >= 0.58)
    .sort((a, b) => b.score - a.score)
    .slice(0, 5);
  if (fuzzy.length === 1 && fuzzy[0].score >= 0.8) return { status: 'possible_match', row: fuzzy[0].row, matches: [fuzzy[0].row.item_name] };
  if (fuzzy.length > 0) return { status: 'ambiguous', matches: fuzzy.map((row) => row.row.item_name) };
  return { status: 'new', matches: [] };
}

const nameKeys = ['item_name', 'item', 'product_name', 'product', 'name', 'title'];
const priceKeys = ['price', 'rate', 'mrp', 'selling_price', 'amount'];
const stockKeys = ['stock', 'qty', 'quantity', 'count', 'inventory'];
const unitKeys = ['unit', 'size', 'pack'];
const categoryKeys = ['category', 'group'];
const brandKeys = ['brand', 'company'];

function pickField(row, keys) {
  const lowered = {};
  for (const [key, value] of Object.entries(row || {})) {
    lowered[String(key).toLowerCase().replace(/[^a-z0-9]+/g, '_')] = value;
  }
  for (const key of keys) {
    if (row[key] !== undefined && row[key] !== null && row[key] !== '') return row[key];
    if (lowered[key] !== undefined && lowered[key] !== null && lowered[key] !== '') return lowered[key];
  }
  return '';
}

const documentConfidence = normalizeConfidence(inputRows[0]?.document_confidence);
const reservedSkus = new Set();
const seenNames = new Set();
const previewRows = [];
const invalidRows = [];
const summary = {
  total_rows: inputRows.length,
  valid_rows: 0,
  new_items: 0,
  updates: 0,
  reactivations: 0,
  invalid_rows: 0,
  ambiguous_rows: 0,
  possible_matches: 0,
  duplicate_rows: 0,
  has_blockers: false,
};
const qualityNotes = [];
if (ocrBacked) {
  if (documentConfidence === null) {
    summary.has_blockers = true;
    qualityNotes.push('Missing document OCR confidence');
  } else if (documentConfidence < documentConfidenceThreshold) {
    summary.has_blockers = true;
    qualityNotes.push('Document OCR confidence below threshold');
  }
}

for (const rawRow of inputRows) {
  const itemName = String(pickField(rawRow, nameKeys) || '').trim();
  const price = toNum(pickField(rawRow, priceKeys));
  const stock = toNum(pickField(rawRow, stockKeys));
  const unit = String(pickField(rawRow, unitKeys) || '').trim();
  const category = String(pickField(rawRow, categoryKeys) || '').trim();
  const brand = String(pickField(rawRow, brandKeys) || '').trim();
  const invalid = rawRow.invalid === true;
  const rowConfidence = normalizeConfidence(rawRow.row_confidence ?? rawRow.confidence ?? rawRow.ocr_confidence);
  const alphaChars = (itemName.match(/[a-z]/gi) || []).length;
  const digitChars = (itemName.match(/\d/g) || []).length;
  const row = {
    raw_line: String(rawRow.raw_line || itemName || '').trim(),
    item_name: itemName,
    normalized_name: normalizeName(itemName),
    price,
    stock,
    unit,
    category,
    brand,
    reason: String(rawRow.reason || '').trim(),
    row_confidence: rowConfidence,
    review_reason: String(rawRow.review_reason || '').trim(),
  };

  const rowBlockers = [];
  if (!itemName) rowBlockers.push('missing item name');
  if (price === null || Number.isNaN(price) || price <= 0) rowBlockers.push('missing or invalid price');
  if (stock === null || Number.isNaN(stock) || stock < 0) rowBlockers.push('missing or invalid stock');
  if (ocrBacked) {
    if (rowConfidence === null) rowBlockers.push('missing OCR confidence');
    else if (rowConfidence < rowConfidenceThreshold) rowBlockers.push('low OCR confidence');
    if (alphaChars < 3) rowBlockers.push('item name too noisy');
    if (digitChars > alphaChars) rowBlockers.push('item name looks misread');
    if (rawRow.needs_review === true) rowBlockers.push('Claude marked row for review');
  }

  if (invalid || rowBlockers.length > 0) {
    previewRows.push({
      ...row,
      action: 'invalid',
      reason: row.reason || row.review_reason || rowBlockers.join(', '),
    });
    invalidRows.push({ ...row, reason: row.reason || row.review_reason || rowBlockers.join(', ') });
    summary.invalid_rows += 1;
    summary.has_blockers = true;
    continue;
  }

  if (seenNames.has(row.normalized_name)) {
    previewRows.push({ ...row, action: 'duplicate_in_batch', reason: 'duplicate row in import' });
    invalidRows.push({ ...row, reason: 'duplicate row in import' });
    summary.duplicate_rows += 1;
    summary.has_blockers = true;
    continue;
  }
  seenNames.add(row.normalized_name);

  const resolution = resolveItem(itemName);
  if (resolution.status === 'exact') {
    previewRows.push({
      ...row,
      action: 'update_existing',
      existing_item_name: resolution.row.item_name,
      existing_sku: String(resolution.row.sku || ''),
      desired_active: true,
    });
    summary.valid_rows += 1;
    summary.updates += 1;
    continue;
  }
  if (resolution.status === 'inactive_exact') {
    previewRows.push({
      ...row,
      action: 'reactivate_existing',
      existing_item_name: resolution.row.item_name,
      existing_sku: String(resolution.row.sku || ''),
      desired_active: true,
    });
    summary.valid_rows += 1;
    summary.reactivations += 1;
    continue;
  }
  if (resolution.status === 'possible_match') {
    previewRows.push({ ...row, action: 'possible_match', match_names: resolution.matches });
    invalidRows.push({ ...row, reason: 'possible match', match_names: resolution.matches });
    summary.possible_matches += 1;
    summary.has_blockers = true;
    continue;
  }
  if (resolution.status === 'ambiguous') {
    previewRows.push({ ...row, action: 'ambiguous', match_names: resolution.matches });
    invalidRows.push({ ...row, reason: 'ambiguous item match', match_names: resolution.matches });
    summary.ambiguous_rows += 1;
    summary.has_blockers = true;
    continue;
  }
  previewRows.push({
    ...row,
    action: 'new_item',
    suggested_sku: buildSku(itemName, inventory, reservedSkus),
    desired_active: true,
  });
  summary.valid_rows += 1;
  summary.new_items += 1;
}

return [{
  json: {
    ...meta,
    action: 'preview_manual',
    preview_rows: previewRows,
    cleanup_summary: summary,
    invalid_rows: invalidRows,
    document_confidence: documentConfidence,
    quality_notes: [
      ...qualityNotes,
      ...inputRows.flatMap((row) => Array.isArray(row.quality_notes) ? row.quality_notes : []),
    ].filter(Boolean),
  },
}];

const d = $('Prepare Import Preview').first().json;
const row = $input.first().json || {};

const parseMaybeJson = (value, fallback) => {
  if (value === undefined || value === null || value === '') return fallback;
  if (Array.isArray(value) || typeof value === 'object') return value;
  try { return JSON.parse(value); } catch { return fallback; }
};

const summary = parseMaybeJson(row.summary, d.cleanup_summary || {});
const previewRows = parseMaybeJson(row.preview_rows, d.preview_rows || []);
const invalidRows = parseMaybeJson(row.invalid_rows, d.invalid_rows || []);
const qualityNotes = parseMaybeJson(d.quality_notes, []);
const sessionId = String(row.session_id || '');
const fileLabel = d.media_filename || 'your file';
const makeButtons = (body, buttons) => ({ chat_id: d.chat_id, message_type: 'button', body_text: body, buttons});
const makeText = (body) => ({ chat_id: d.chat_id, message_type: 'text', body_text: body});

if (row.result !== 'preview_created') {
  return [{ json: makeText('I could not prepare the inventory import preview safely. Please try the upload again.') }];
}

const lines = [];
for (const entry of previewRows.slice(0, 8)) {
  if (entry.action === 'new_item') {
    lines.push('- New: ' + entry.item_name + ' (SKU ' + entry.suggested_sku + ', Rs.' + Number(entry.price || 0).toFixed(2) + ', stock ' + Number(entry.stock || 0) + ')');
  } else if (entry.action === 'update_existing') {
    lines.push('- Update: ' + entry.existing_item_name + ' -> Rs.' + Number(entry.price || 0).toFixed(2) + ', stock ' + Number(entry.stock || 0));
  } else if (entry.action === 'reactivate_existing') {
    lines.push('- Reactivate: ' + entry.existing_item_name + ' -> Rs.' + Number(entry.price || 0).toFixed(2) + ', stock ' + Number(entry.stock || 0));
  } else if (entry.action === 'possible_match' || entry.action === 'ambiguous') {
    lines.push('- Review: ' + entry.item_name + ' may match ' + (entry.match_names || []).join(', '));
  } else if (entry.action === 'duplicate_in_batch') {
    lines.push('- Duplicate row: ' + entry.item_name);
  } else {
    lines.push('- Invalid: ' + (entry.raw_line || entry.item_name || 'row'));
  }
}

const invalidCount = invalidRows.length ? '\nInvalid rows: ' + invalidRows.length : '';
const qualityLine = qualityNotes.length ? '\nQuality notes: ' + qualityNotes.slice(0, 3).join('; ') : '';
if (summary.has_blockers) {
  return [{ json: makeButtons(
    'I parsed ' + fileLabel + ' and found blockers.\n\n' + lines.join('\n') + invalidCount + qualityLine + '\n\nNo catalog changes were applied. Fix the file and upload it again or send a clearer XLS/XLSX/image.',
    [
      { id: 'owner_catalog_import', title: 'Upload again' },
      { id: 'owner_inv_cancel__' + sessionId, title: 'Cancel' },
    ],
  ) }];
}

return [{ json: makeButtons(
  'Import preview for ' + fileLabel + ':\n\n' + lines.join('\n') + invalidCount + '\n\nConfirm to apply these catalog changes.',
  [
    { id: 'owner_inv_confirm__' + sessionId, title: 'Confirm import' },
    { id: 'owner_inv_cancel__' + sessionId, title: 'Cancel' },
  ],
) }];

const input = $input.first();
const raw = ($json.tool_input && typeof $json.tool_input === 'object') ? $json.tool_input : $json;
const message = String(raw.message || raw.media_caption || '').trim();
const fileName = String(raw.media_filename || '').trim();
const mime = String(raw.media_mime_type || '').trim().toLowerCase();
const ext = fileName.includes('.') ? fileName.split('.').pop().toLowerCase() : '';
const sourceType = String(raw.source_type || (raw.media_id ? 'document' : 'text')).trim() || 'text';
return [{
  json: {
    ...raw,
    chat_id: String(raw.chat_id || ''),
    store_id: raw.store_id || null,
    message,
    source_type: sourceType,
    media_id: String(raw.media_id || ''),
    media_mime_type: mime,
    media_filename: fileName,
    media_caption: String(raw.media_caption || ''),
    media_ext: ext,
    test_file_base64: String(raw.test_file_base64 || ''),
    test_file_name: String(raw.test_file_name || fileName || ''),
    test_file_mime_type: String(raw.test_file_mime_type || mime || ''),
    test_mode: raw.test_mode === true,
  },
  binary: input?.binary || {},
}];

