}

return [{
  json: {
    ...d,
    route,
    parse_mode,
    error_message,
  },
  binary,
}];

const input = $input.first();
const d = $('Determine Import Source').first().json || {};
if (String(d.test_file_base64 || '').trim()) {
  return [{
    json: d,
    binary: {
      data: {
        data: String(d.test_file_base64 || ''),
        mimeType: String(d.test_file_mime_type || d.media_mime_type || 'application/octet-stream'),
        fileName: String(d.test_file_name || d.media_filename || 'owner_upload'),
      },
    },
